import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"Trajectory 번들","description":"OpenClaw agent 세션 디버깅을 위한 비식별화된 trajectory 번들 내보내기","frontmatter":{"title":"Trajectory 번들","description":"OpenClaw agent 세션 디버깅을 위한 비식별화된 trajectory 번들 내보내기"},"headers":[],"relativePath":"tools/trajectory.md","filePath":"tools/trajectory.md","lastUpdated":null}'),l={name:"tools/trajectory.md"};function o(p,t,n,d,c,r){return a(),s("div",null,[...t[0]||(t[0]=[i(`<p>Trajectory 캡처는 OpenClaw의 세션별 비행 기록 장치(flight recorder)입니다. 각 agent 실행에 대해 구조화된 타임라인을 기록한 다음, <code>/export-trajectory</code>가 현재 세션을 비식별화된 지원(support) 번들로 패키징합니다.</p><p>다음과 같은 질문에 답해야 할 때 사용하세요:</p><ul><li>어떤 프롬프트, 시스템 프롬프트, 그리고 tools가 모델에 전송되었는가?</li><li>어떤 트랜스크립트 메시지와 tool 호출이 이 답변으로 이어졌는가?</li><li>실행이 타임아웃되었거나, 중단되었거나, 컴팩트되었거나, 프로바이더 오류를 겪었는가?</li><li>어떤 모델, plugins, skills, 런타임 설정이 활성화되어 있었는가?</li><li>프로바이더가 어떤 사용량 및 prompt-cache 메타데이터를 반환했는가?</li></ul><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><p>활성 세션에서 다음을 전송하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/export-trajectory</span></span></code></pre></div><p>별칭:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/trajectory</span></span></code></pre></div><p>OpenClaw는 워크스페이스 아래에 번들을 기록합니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.openclaw/trajectory-exports/openclaw-trajectory-&lt;session&gt;-&lt;timestamp&gt;/</span></span></code></pre></div><p>상대 출력 디렉터리 이름을 선택할 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/export-trajectory bug-1234</span></span></code></pre></div><p>커스텀 경로는 <code>.openclaw/trajectory-exports/</code> 내부에서 해석됩니다. 절대 경로와 <code>~</code> 경로는 거부됩니다.</p><h2 id="접근-권한" tabindex="-1">접근 권한 <a class="header-anchor" href="#접근-권한" aria-label="Permalink to &quot;접근 권한&quot;">​</a></h2><p>Trajectory 내보내기는 오너(owner) 명령입니다. 송신자는 채널에 대한 일반적인 명령 인증 검사와 오너 검사를 통과해야 합니다.</p><h2 id="기록되는-내용" tabindex="-1">기록되는 내용 <a class="header-anchor" href="#기록되는-내용" aria-label="Permalink to &quot;기록되는 내용&quot;">​</a></h2><p>Trajectory 캡처는 OpenClaw agent 실행에 대해 기본적으로 켜져 있습니다.</p><p>런타임 이벤트에는 다음이 포함됩니다:</p><ul><li><code>session.started</code></li><li><code>trace.metadata</code></li><li><code>context.compiled</code></li><li><code>prompt.submitted</code></li><li><code>model.completed</code></li><li><code>trace.artifacts</code></li><li><code>session.ended</code></li></ul><p>트랜스크립트 이벤트도 활성 세션 브랜치에서 재구성됩니다:</p><ul><li>사용자 메시지</li><li>어시스턴트 메시지</li><li>tool 호출</li><li>tool 결과</li><li>컴팩션(compaction)</li><li>모델 변경</li><li>레이블 및 커스텀 세션 항목</li></ul><p>이벤트는 다음 스키마 마커와 함께 JSON Lines로 기록됩니다:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;traceSchema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openclaw-trajectory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;schemaVersion&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="번들-파일" tabindex="-1">번들 파일 <a class="header-anchor" href="#번들-파일" aria-label="Permalink to &quot;번들 파일&quot;">​</a></h2><p>내보내진 번들에는 다음 파일들이 포함될 수 있습니다:</p><table tabindex="0"><thead><tr><th>파일</th><th>내용</th></tr></thead><tbody><tr><td><code>manifest.json</code></td><td>번들 스키마, 소스 파일, 이벤트 수, 생성된 파일 목록</td></tr><tr><td><code>events.jsonl</code></td><td>순서대로 정렬된 런타임 및 트랜스크립트 타임라인</td></tr><tr><td><code>session-branch.json</code></td><td>비식별화된 활성 트랜스크립트 브랜치 및 세션 헤더</td></tr><tr><td><code>metadata.json</code></td><td>OpenClaw 버전, OS/런타임, 모델, 구성 스냅샷, plugins, skills, 프롬프트 메타데이터</td></tr><tr><td><code>artifacts.json</code></td><td>최종 상태, 오류, 사용량, prompt cache, 컴팩션 횟수, 어시스턴트 텍스트, tool 메타데이터</td></tr><tr><td><code>prompts.json</code></td><td>제출된 프롬프트 및 선택된 프롬프트 빌드 세부 정보</td></tr><tr><td><code>system-prompt.txt</code></td><td>캡처된 경우 최신 컴파일된 시스템 프롬프트</td></tr><tr><td><code>tools.json</code></td><td>캡처된 경우 모델에 전송된 tool 정의</td></tr></tbody></table><p><code>manifest.json</code>은 해당 번들에 존재하는 파일들을 나열합니다. 세션이 해당 런타임 데이터를 캡처하지 않은 경우 일부 파일은 생략됩니다.</p><h2 id="캡처-위치" tabindex="-1">캡처 위치 <a class="header-anchor" href="#캡처-위치" aria-label="Permalink to &quot;캡처 위치&quot;">​</a></h2><p>기본적으로, 런타임 trajectory 이벤트는 세션 파일 옆에 기록됩니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;session&gt;.trajectory.jsonl</span></span></code></pre></div><p>OpenClaw는 세션 옆에 best-effort 포인터 파일도 기록합니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;session&gt;.trajectory-path.json</span></span></code></pre></div><p>전용 디렉터리에 런타임 trajectory 사이드카 파일을 저장하려면 <code>OPENCLAW_TRAJECTORY_DIR</code>을 설정하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCLAW_TRAJECTORY_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/var/lib/openclaw/trajectories</span></span></code></pre></div><p>이 변수가 설정되면, OpenClaw는 해당 디렉터리에 세션 id별로 하나의 JSONL 파일을 기록합니다.</p><h2 id="캡처-비활성화" tabindex="-1">캡처 비활성화 <a class="header-anchor" href="#캡처-비활성화" aria-label="Permalink to &quot;캡처 비활성화&quot;">​</a></h2><p>OpenClaw를 시작하기 전에 <code>OPENCLAW_TRAJECTORY=0</code>을 설정하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCLAW_TRAJECTORY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><p>이는 런타임 trajectory 캡처를 비활성화합니다. <code>/export-trajectory</code>는 여전히 트랜스크립트 브랜치를 내보낼 수 있지만, 컴파일된 컨텍스트, 프로바이더 아티팩트, 프롬프트 메타데이터 같은 런타임 전용 파일은 누락될 수 있습니다.</p><h2 id="프라이버시-및-제한" tabindex="-1">프라이버시 및 제한 <a class="header-anchor" href="#프라이버시-및-제한" aria-label="Permalink to &quot;프라이버시 및 제한&quot;">​</a></h2><p>Trajectory 번들은 지원 및 디버깅용으로 설계되었으며, 공개 게시용이 아닙니다. OpenClaw는 내보내기 파일을 작성하기 전에 민감한 값을 비식별화합니다:</p><ul><li>자격 증명 및 알려진 secret 유사 payload 필드</li><li>이미지 데이터</li><li>로컬 상태 경로</li><li>워크스페이스 경로, <code>$WORKSPACE_DIR</code>로 치환됨</li><li>감지된 경우 홈 디렉터리 경로</li></ul><p>내보내기 도구는 입력 크기도 제한합니다:</p><ul><li>런타임 사이드카 파일: 50 MiB</li><li>세션 파일: 50 MiB</li><li>런타임 이벤트: 200,000</li><li>총 내보낸 이벤트: 250,000</li><li>개별 런타임 이벤트 라인은 256 KiB를 초과하면 잘립니다</li></ul><p>팀 외부로 번들을 공유하기 전에 검토하세요. 비식별화는 best-effort이며 모든 애플리케이션별 secret을 알 수는 없습니다.</p><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><p>내보내기에 런타임 이벤트가 없는 경우:</p><ul><li>OpenClaw가 <code>OPENCLAW_TRAJECTORY=0</code> 없이 시작되었는지 확인하세요</li><li><code>OPENCLAW_TRAJECTORY_DIR</code>이 쓰기 가능한 디렉터리를 가리키는지 확인하세요</li><li>세션에서 다른 메시지를 실행한 다음 다시 내보내세요</li><li><code>manifest.json</code>에서 <code>runtimeEventCount</code>를 확인하세요</li></ul><p>명령이 출력 경로를 거부하는 경우:</p><ul><li><code>bug-1234</code>와 같은 상대 이름을 사용하세요</li><li><code>/tmp/...</code> 또는 <code>~/...</code>을 전달하지 마세요</li><li>내보내기를 <code>.openclaw/trajectory-exports/</code> 내부에 유지하세요</li></ul><p>내보내기가 크기 오류로 실패하는 경우, 세션 또는 사이드카가 내보내기 안전 제한을 초과한 것입니다. 새 세션을 시작하거나 더 작은 재현을 내보내세요.</p><h2 id="관련" tabindex="-1">관련 <a class="header-anchor" href="#관련" aria-label="Permalink to &quot;관련&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/diffs">Diffs</a></li><li><a href="/openclaw-docs-ko/concepts/session">세션 관리</a></li><li><a href="/openclaw-docs-ko/tools/exec">Exec tool</a></li></ul>`,53)])])}const k=e(l,[["render",o]]);export{u as __pageData,k as default};
